import React, { ReactElement, useRef, useState } from "react";
import axios from "axios";
import { useToasts } from "react-toast-notifications";
import Lottie from "react-lottie";

const defaultOptions = (animation: string) => ({
  loop: true,
  autoplay: true,
  animationData: require(`../public/animations/${animation}.json`),
  rendererSettings: {
    preserveAspectRatio: "xMidYMid slice",
  },
});

function validateEmail(email: string) {
  const re =
    /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
  return re.test(String(email).toLowerCase());
}

export default function Contact(): ReactElement {
  const nameRef = useRef<HTMLInputElement>(null);
  const emailRef = useRef<HTMLInputElement>(null);
  const messageRef = useRef<HTMLTextAreaElement>(null);
  const [loading, setLoading] = React.useState(false);

  const [errors, setErrors] = useState<string[]>([]);

  const { addToast } = useToasts();

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (
      !nameRef.current.value &&
      !emailRef.current.value &&
      !messageRef.current.value
    ) {
      return;
    }

    const data = new FormData();
    data.append("name", nameRef.current.value);
    data.append("email", emailRef.current.value);
    data.append("message", messageRef.current.value);
    setLoading(true);
    try {
      await axios.post("https://formspree.io/f/mleazznz", data, {
        headers: { Accept: "application/json" },
      });
      addToast("Mail Sent Successfully", { appearance: "success" });
      nameRef.current.value = "";
      emailRef.current.value = "";
      messageRef.current.value = "";
    } catch (err) {
      addToast("Error", { appearance: "error" });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div id="contact" className="contact">
      <h1>Contact Me</h1>
      <main>
        <form onSubmit={handleSubmit}>
          {errors.map((err: string) => (
            <div className="error">{err}</div>
          ))}
          <div className="input">
            <label htmlFor="name">Name:</label>
            <input ref={nameRef} type="text" id="name" />
          </div>
          <div className="input">
            <label htmlFor="email">Email:</label>
            <input ref={emailRef} type="text" id="email" />
          </div>
          <div className="input">
            <label htmlFor="message">Message:</label>
            <textarea ref={messageRef} id="message" />
          </div>
          <button disabled={loading}>
            Submit
            <Lottie
              options={defaultOptions("loading")}
              height={50}
              width={50}
            />
          </button>
        </form>
      </main>
      <div className="social">
        <a href="https://github.com/akh-47">
          <i className="fab fa-github"></i>
          Github
        </a>
        <a href="https://www.linkedin.com/in/akhil-kala-b185131b0/">
          <i className="fab fa-linkedin"></i>
          Linkedin
        </a>
        <a href="https://twitter.com/akhilkala1">
          <i className="fab fa-twitter"></i>
          Twitter
        </a>
        <a>
          <i className="fab fa-dev"></i>
          Dev
        </a>
        <a>
          <i className="fas fa-envelope"></i>
          Mail
        </a>
        <a>
          <i className="fas fa-file-alt"></i>
          Resume
        </a>
      </div>
      <footer>Designed and Developed by Akhil Kala</footer>
    </div>
  );
}
